script:
  // 🔴 PENTING: Ganti dengan URL Google Apps Script Anda (Wajib deploy "Versi Baru" setelah edit backend tadi)
  const AUTH_SCRIPT_URL = 'https://script.google.com/macros/s/AKfycbyYn-DVnvWkTyjK0VgmuVvVSVODnzRUT6s_hwx_ymMDi9bTMCMs7CpcVrbuh071BXpopA/exec';

  let currentMode = 'login';
  let loggedInUser = null;
  let currentToko = null; 
  let editMap = null;
  let editMarker = null;

  document.addEventListener("DOMContentLoaded", function() { cekSesiUser(); });

  function handleRoleChange() {
      if (currentMode !== 'register') return;
      document.getElementById('inpNama').setAttribute('required', 'true');
      document.getElementById('inpWa').setAttribute('required', 'true');
      document.getElementById('inpPass').setAttribute('required', 'true');
  }

  function cekSesiUser() {
      const sesiString = localStorage.getItem('anturun_session');
      if (sesiString) {
          loggedInUser = JSON.parse(sesiString);

          if (!loggedInUser.userId) {
              localStorage.removeItem('anturun_session');
              loggedInUser = null;
              document.getElementById('panelAuth').classList.remove('hidden');
              document.getElementById('panelLoggedIn').classList.replace('flex', 'hidden');
              showMessage("Sistem telah diperbarui. Silakan Daftar ulang atau Masuk.", "error");
              return;
          }

          document.getElementById('panelAuth').classList.add('hidden');
          document.getElementById('panelLoggedIn').classList.replace('hidden', 'flex');
          
          document.getElementById('userIdTxt').innerText = loggedInUser.userId || '-'; 
          document.getElementById('userRoleTxt').innerText = loggedInUser.role || '-';
          document.getElementById('userNameTxt').innerText = loggedInUser.nama || '-';
          document.getElementById('userWaTxt').innerText = loggedInUser.wa || '-';
          
          if(loggedInUser.role === 'Merchant') {
              fetchTokoInfo();
          } else {
              document.getElementById('tokoInfoContainer').classList.add('hidden');
          }
          
          toggleEditProfile(false);
          toggleEditToko(false);
      } else {
          document.getElementById('panelAuth').classList.remove('hidden');
          document.getElementById('panelLoggedIn').classList.replace('flex', 'hidden');
      }
  }

  function fetchTokoInfo() {
      if(!loggedInUser || loggedInUser.role !== 'Merchant') return;
      document.getElementById('tokoInfoContainer').classList.remove('hidden');
      
      const payload = { action: 'get_toko_info', userId: loggedInUser.userId }; 
      
      fetch(AUTH_SCRIPT_URL, {
          method: 'POST', redirect: 'follow',
          headers: { 'Content-Type': 'text/plain;charset=utf-8' },
          body: JSON.stringify(payload)
      })
      .then(res => res.json())
      .then(data => {
          if (data.status === 'success' && data.toko) {
              currentToko = data.toko;
              // Update Text & Hilangkan italic styling
              document.getElementById('tokoNamaTxt').classList.remove('text-gray-400', 'italic');
              document.getElementById('tokoJamTxt').classList.remove('text-gray-400', 'italic');
              document.getElementById('tokoAlamatTxt').classList.remove('text-gray-400', 'italic');
              document.getElementById('tokoKordinatTxt').classList.remove('text-gray-400', 'italic');
              
              document.getElementById('tokoNamaTxt').innerText = currentToko.namaToko;
              document.getElementById('tokoJamTxt').innerText = currentToko.jamBuka;
              document.getElementById('tokoAlamatTxt').innerText = currentToko.alamat;
              document.getElementById('tokoKordinatTxt').innerText = currentToko.kordinat || 'Belum diatur';
          } else {
              currentToko = { namaToko: '', jamBuka: '', alamat: '', kordinat: '' };
              document.getElementById('tokoNamaTxt').classList.add('text-gray-400', 'italic');
              document.getElementById('tokoJamTxt').classList.add('text-gray-400', 'italic');
              document.getElementById('tokoAlamatTxt').classList.add('text-gray-400', 'italic');
              document.getElementById('tokoKordinatTxt').classList.add('text-gray-400', 'italic');
              
              document.getElementById('tokoNamaTxt').innerText = 'Belum diatur';
              document.getElementById('tokoJamTxt').innerText = 'Belum diatur';
              document.getElementById('tokoAlamatTxt').innerText = 'Belum diatur';
              document.getElementById('tokoKordinatTxt').innerText = 'Belum diatur';
          }
      }).catch(err => console.error(err));
  }

  // --- INISIALISASI LEAFLET MAP ---
  function initEditMap() {
      // Default Jakarta
      let lat = -6.200000;
      let lng = 106.816666;

      if (currentToko && currentToko.kordinat) {
          const parts = currentToko.kordinat.split(',');
          if (parts.length === 2) {
              lat = parseFloat(parts[0].trim());
              lng = parseFloat(parts[1].trim());
              document.getElementById('editTokoKordinatInp').value = currentToko.kordinat;
          }
      }

      if (!editMap) {
          editMap = L.map('mapEditToko').setView([lat, lng], 15);
          L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', { maxZoom: 19 }).addTo(editMap);
          editMarker = L.marker([lat, lng], {draggable: true}).addTo(editMap);

          editMarker.on('dragend', function() {
              const pos = editMarker.getLatLng();
              document.getElementById('editTokoKordinatInp').value = pos.lat.toFixed(6) + ", " + pos.lng.toFixed(6);
          });
          editMap.on('click', function(e) {
              editMarker.setLatLng(e.latlng);
              document.getElementById('editTokoKordinatInp').value = e.latlng.lat.toFixed(6) + ", " + e.latlng.lng.toFixed(6);
          });
      } else {
          editMap.setView([lat, lng], 15);
          editMarker.setLatLng([lat, lng]);
      }
      
      // Fix bug peta blank/terpotong karena div disembunyikan sebelumnya
      setTimeout(() => { editMap.invalidateSize(); }, 300);
  }

  function lacakLokasiEdit() {
      if (navigator.geolocation) {
          navigator.geolocation.getCurrentPosition(
              (pos) => {
                  const lat = pos.coords.latitude;
                  const lng = pos.coords.longitude;
                  if (editMap && editMarker) {
                      editMap.setView([lat, lng], 16);
                      editMarker.setLatLng([lat, lng]);
                      document.getElementById('editTokoKordinatInp').value = lat.toFixed(6) + ", " + lng.toFixed(6);
                  }
              },
              () => alert("Gagal mendapatkan lokasi GPS. Pastikan izin lokasi aktif."),
              { enableHighAccuracy: true }
          );
      } else { alert("Browser Anda tidak mendukung deteksi lokasi."); }
  }

  function togglePasswordFields() {
      const passContainer = document.getElementById('passwordFieldsContainer');
      const btnToggle = document.getElementById('btnTogglePass');
      if (passContainer.classList.contains('hidden')) {
          passContainer.classList.remove('hidden');
          btnToggle.innerHTML = 'Batal Ubah Kata Sandi';
          btnToggle.classList.add('bg-gray-200');
      } else {
          passContainer.classList.add('hidden');
          btnToggle.innerHTML = '🔒 Ubah Kata Sandi';
          btnToggle.classList.remove('bg-gray-200');
          document.getElementById('editPassOld').value = '';
          document.getElementById('editPassNew').value = '';
      }
  }

  function toggleEditProfile(isEditMode) {
      const viewData = document.getElementById('viewProfileData');
      const editProfile = document.getElementById('editProfileData');
      const editToko = document.getElementById('editTokoData');
      document.getElementById('profileMessage').classList.add('hidden'); 
      
      if (isEditMode && loggedInUser) {
          viewData.classList.add('hidden'); editToko.classList.add('hidden'); editProfile.classList.remove('hidden');
          document.getElementById('editWa').value = loggedInUser.wa;
          document.getElementById('editNama').value = loggedInUser.nama;
          
          document.getElementById('passwordFieldsContainer').classList.add('hidden');
          document.getElementById('btnTogglePass').innerHTML = '🔒 Ubah Kata Sandi';
          document.getElementById('btnTogglePass').classList.remove('bg-gray-200');
          document.getElementById('editPassOld').value = ''; document.getElementById('editPassNew').value = ''; 
      } else {
          editProfile.classList.add('hidden');
          if(!editToko.classList.contains('hidden')) return; 
          viewData.classList.remove('hidden');
      }
  }

  function toggleEditToko(isEditMode) {
      const viewData = document.getElementById('viewProfileData');
      const editProfile = document.getElementById('editProfileData');
      const editToko = document.getElementById('editTokoData');
      document.getElementById('profileMessage').classList.add('hidden'); 
      
      if (isEditMode && currentToko) {
          viewData.classList.add('hidden'); editProfile.classList.add('hidden'); editToko.classList.remove('hidden');
          document.getElementById('editTokoNamaInp').value = currentToko.namaToko;
          document.getElementById('editTokoJamInp').value = currentToko.jamBuka;
          document.getElementById('editTokoAlamatInp').value = currentToko.alamat;
          document.getElementById('editTokoKordinatInp').value = currentToko.kordinat || '';
          
          // Render Map
          initEditMap();
      } else {
          editToko.classList.add('hidden');
          if(!editProfile.classList.contains('hidden')) return; 
          viewData.classList.remove('hidden');
      }
  }

  function logoutUser() {
      localStorage.removeItem('anturun_session');
      loggedInUser = null; currentToko = null;
      cekSesiUser(); showMessage("Anda berhasil keluar.", "success");
  }

  function switchTab(mode) {
      currentMode = mode;
      const tabLogin = document.getElementById('tabLogin'), tabRegister = document.getElementById('tabRegister');
      const regFields = document.getElementById('registerFields'), btnSubmit = document.getElementById('btnSubmitAuth');
      document.getElementById('authMessage').classList.add('hidden');
      
      if (mode === 'login') {
          tabLogin.className = "flex-1 py-2 font-bold text-sm border-b-2 border-[#EE4D2D] text-[#EE4D2D] outline-none";
          tabRegister.className = "flex-1 py-2 font-bold text-sm border-b-2 border-transparent text-gray-500 outline-none";
          regFields.classList.add('hidden'); document.getElementById('wrapperNamaLengkap').classList.add('hidden');
          document.getElementById('inpNama').removeAttribute('required'); btnSubmit.innerText = "Masuk Sekarang";
      } else {
          tabRegister.className = "flex-1 py-2 font-bold text-sm border-b-2 border-[#EE4D2D] text-[#EE4D2D] outline-none";
          tabLogin.className = "flex-1 py-2 font-bold text-sm border-b-2 border-transparent text-gray-500 outline-none";
          regFields.classList.remove('hidden'); document.getElementById('wrapperNamaLengkap').classList.remove('hidden');
          btnSubmit.innerText = "Daftar Akun"; handleRoleChange();
      }
  }

  function showMessage(text, type, targetElId = 'authMessage') {
      const msgEl = document.getElementById(targetElId);
      msgEl.innerHTML = text;
      msgEl.classList.remove('hidden', 'bg-red-100', 'text-red-700', 'bg-green-100', 'text-green-700');
      if (type === 'error') msgEl.classList.add('bg-red-100', 'text-red-700'); else msgEl.classList.add('bg-green-100', 'text-green-700');
  }

  document.getElementById('formAuth').addEventListener('submit', function(e) {
      e.preventDefault();
      document.getElementById('authMessage').classList.add('hidden'); document.getElementById('authLoading').classList.replace('hidden', 'flex');
      
      const payload = { action: currentMode === 'login' ? 'login' : 'register_user', wa: document.getElementById('inpWa').value.trim(), password: document.getElementById('inpPass').value.trim() };
      if (currentMode === 'register') { payload.nama = document.getElementById('inpNama').value.trim(); payload.role = document.querySelector('input[name="role"]:checked').value; }

      fetch(AUTH_SCRIPT_URL, { method: 'POST', redirect: 'follow', headers: { 'Content-Type': 'text/plain;charset=utf-8' }, body: JSON.stringify(payload) })
      .then(async res => { const text = await res.text(); try { return JSON.parse(text); } catch(err) { throw new Error("Respon Server Tidak Valid."); } })
      .then(data => {
          document.getElementById('authLoading').classList.replace('flex', 'hidden');
          if (data.status === 'success') {
              if (data.statusAkun === 'Pending') showMessage(`Pendaftaran Driver Berhasil!
Menunggu verifikasi admin.`, "success", "authMessage");
              else { localStorage.setItem('anturun_session', JSON.stringify(data.user)); showMessage(data.message, "success", "authMessage"); setTimeout(() => { cekSesiUser(); document.getElementById('formAuth').reset(); }, 1000); }
          } else showMessage(data.message, "error", "authMessage");
      }).catch(err => { document.getElementById('authLoading').classList.replace('flex', 'hidden'); showMessage("Koneksi Gagal.", "error", "authMessage"); });
  });

  document.getElementById('formEditProfile').addEventListener('submit', function(e) {
      e.preventDefault();
      const passBaru = document.getElementById('editPassNew').value.trim(), passLama = document.getElementById('editPassOld').value.trim();
      if (passBaru !== "" && passLama === "") { showMessage("Masukkan Kata Sandi Lama untuk mengubah ke Kata Sandi Baru!", "error", "profileMessage"); document.getElementById('editPassOld').focus(); return; }
      
      document.getElementById('authLoading').classList.replace('hidden', 'flex');
      const payload = { action: 'edit_user', userId: loggedInUser.userId, oldWa: loggedInUser.wa, newWa: document.getElementById('editWa').value.trim(), nama: document.getElementById('editNama').value.trim(), oldPassword: passLama, newPassword: passBaru };

      fetch(AUTH_SCRIPT_URL, { method: 'POST', redirect: 'follow', headers: { 'Content-Type': 'text/plain;charset=utf-8' }, body: JSON.stringify(payload) })
      .then(res => res.json()).then(data => {
          document.getElementById('authLoading').classList.replace('flex', 'hidden');
          if (data.status === 'success') { localStorage.setItem('anturun_session', JSON.stringify(data.user)); toggleEditProfile(false); cekSesiUser(); showMessage(data.message, "success", "profileMessage"); } else showMessage(data.message, "error", "profileMessage");
      }).catch(err => { document.getElementById('authLoading').classList.replace('flex', 'hidden'); showMessage("Gagal menyimpan profil.", "error", "profileMessage"); });
  });

  document.getElementById('formEditToko').addEventListener('submit', function(e) {
      e.preventDefault();
      document.getElementById('authLoading').classList.replace('hidden', 'flex');
      const payload = { 
        action: 'edit_toko_info', 
        userId: loggedInUser.userId, 
        namaToko: document.getElementById('editTokoNamaInp').value.trim(), 
        jamBuka: document.getElementById('editTokoJamInp').value.trim(), 
        alamat: document.getElementById('editTokoAlamatInp').value.trim(),
        kordinat: document.getElementById('editTokoKordinatInp').value.trim() // <--- Payload kordinat dikirim
      };

      fetch(AUTH_SCRIPT_URL, { method: 'POST', redirect: 'follow', headers: { 'Content-Type': 'text/plain;charset=utf-8' }, body: JSON.stringify(payload) })
      .then(res => res.json()).then(data => {
          document.getElementById('authLoading').classList.replace('flex', 'hidden');
          if (data.status === 'success') { toggleEditToko(false); fetchTokoInfo(); showMessage(data.message, "success", "profileMessage"); } else showMessage(data.message, "error", "profileMessage");
      }).catch(err => { document.getElementById('authLoading').classList.replace('flex', 'hidden'); showMessage("Gagal menyimpan Info Toko.", "error", "profileMessage"); });
  });
